import json,sys,urllib.request,time,re
K=sys.argv[1]; B='https://irynakarmazina.app.n8n.cloud/api/v1/'; WID='1YdXnLFOXI85IsWv'
def GET(w):
    for a in range(8):
        try: return json.load(urllib.request.urlopen(urllib.request.Request(B+w,headers={'X-N8N-API-KEY':K}),timeout=15))
        except Exception: time.sleep(3)
    return None
d=GET('workflows/'+WID)
if not d: print('GET fail'); sys.exit()
node=[n for n in d['nodes'] if n.get('type')=='n8n-nodes-base.code' and 'work-start' in (n.get('parameters') or {}).get('jsCode','')][0]
c=node['parameters']['jsCode']; open('/root/wf-backup-dash-refresh.js','w').write(c)
before=c
c,n1=re.subn(r'<meta http-equiv="refresh"[^>]*>','',c)
c=c.replace('Оновлюється авто кожні 3 хв.','Оновлення — перезавантажте сторінку (F5).')
c2diff = (c!=before)
print('прибрано meta-refresh:',n1,'| текст оновлено:', 'F5' in c)
if n1>=1 or c2diff:
    node['parameters']['jsCode']=c
    payload={'name':d['name'],'nodes':d['nodes'],'connections':d['connections'],'settings':d.get('settings',{})}
    if d.get('staticData') is not None: payload['staticData']=d['staticData']
    body=json.dumps(payload).encode('utf-8')
    ok=False
    for a in range(4):
        try: r=urllib.request.urlopen(urllib.request.Request(B+'workflows/'+WID,data=body,method='PUT',headers={'X-N8N-API-KEY':K,'Content-Type':'application/json'}),timeout=45); print('PUT',r.status); ok=True; break
        except Exception: time.sleep(3)
    if ok:
        try: urllib.request.urlopen(urllib.request.Request(B+'workflows/'+WID+'/activate',method='POST',headers={'X-N8N-API-KEY':K}),timeout=20); print('activate ok')
        except Exception: pass
        d2=GET('workflows/'+WID)
        if d2:
            cc=[x for x in d2['nodes'] if x.get('type')=='n8n-nodes-base.code' and 'work-start' in (x.get('parameters') or {}).get('jsCode','')][0]['parameters']['jsCode']
            print('verify: refresh прибрано:', 'http-equiv="refresh"' not in cc)
else:
    print('meta-refresh не знайдено — можливо вже прибрано')

PYEOF
